import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    min_distance = float('inf')
    best_node = None

    for idx, customer_pos in enumerate(unvisited_customers):
        total_distance = np.linalg.norm(cur_truck_pos - customer_pos)
        for other_truck_pos in all_truck_pos:
            distance_other_truck = np.linalg.norm(other_truck_pos - customer_pos)
            if distance_other_truck < total_distance:
                total_distance = distance_other_truck
        if total_distance < min_distance:
            min_distance = total_distance
            best_node = idx

    return best_node
